<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\EvidenceRepositoryInterface;use App\DTO\ControlEscaneres\{ScannerEvidenceMetadata,AuthenticatedActorData};
final class PdoEvidenceRepository extends AbstractPdoRepository implements EvidenceRepositoryInterface{public function create(ScannerEvidenceMetadata$d):int{$this->stmt('INSERT INTO scanner_evidencias(scanner_id,movimiento_id,inspeccion_id,incidencia_id,tipo,ruta_storage,mime_type,tamano_bytes,hash_sha256,capturada_at,registrada_por,activo)VALUES(:s,:m,:n,:i,:t,:r,:y,:b,:h,:a,:u,1)',['s'=>$d->scannerId,'m'=>$d->movementId,'n'=>$d->inspectionId,'i'=>$d->incidentId,'t'=>$d->type,'r'=>$d->storagePath,'y'=>$d->mimeType,'b'=>$d->sizeBytes,'h'=>$d->sha256,'a'=>$d->capturedAt->format('Y-m-d H:i:s.u'),'u'=>$d->actor->userId]);return(int)$this->pdo->lastInsertId();}private function map(array$r):ScannerEvidenceMetadata{return new ScannerEvidenceMetadata($r['scanner_id']===null?null:(int)$r['scanner_id'],$r['tipo'],$r['ruta_storage'],$r['mime_type'],(int)$r['tamano_bytes'],$r['hash_sha256'],$this->date($r['capturada_at']),new AuthenticatedActorData((int)$r['registrada_por'],'persisted'),$r['movimiento_id']===null?null:(int)$r['movimiento_id'],$r['inspeccion_id']===null?null:(int)$r['inspeccion_id'],$r['incidencia_id']===null?null:(int)$r['incidencia_id']);}private function many(string$q,int$id):array{return array_map(fn($r)=>$this->map($r),$this->stmt($q,['i'=>$id])->fetchAll(\PDO::FETCH_ASSOC));}public function findById(int$id):?ScannerEvidenceMetadata{$r=$this->stmt('SELECT * FROM scanner_evidencias WHERE id=:i',['i'=>$id])->fetch(\PDO::FETCH_ASSOC);return is_array($r)?$this->map($r):null;}public function listByScannerId(int$id):array{return$this->many('SELECT * FROM scanner_evidencias WHERE scanner_id=:i AND activo=1',$id);}public function listByMovementId(int$id):array{return$this->many('SELECT * FROM scanner_evidencias WHERE movimiento_id=:i AND activo=1',$id);}public function listByInspectionId(int$id):array{return$this->many('SELECT * FROM scanner_evidencias WHERE inspeccion_id=:i AND activo=1',$id);}public function listByIncidentId(int$id):array{return$this->many('SELECT * FROM scanner_evidencias WHERE incidencia_id=:i AND activo=1',$id);}public function deactivate(int$id,int$actor):void{$this->stmt('UPDATE scanner_evidencias SET activo=0 WHERE id=:i',['i'=>$id]);}}
